import{_ as r,o,c as a,a1 as d}from"./chunks/framework.BX4nIuL2.js";const b=JSON.parse('{"title":"移动机器人软硬件集成课程 (AI & ROS 2)","description":"","frontmatter":{},"headers":[],"relativePath":"courses/mobile-robot/index.md","filePath":"courses/mobile-robot/index.md"}'),e={name:"courses/mobile-robot/index.md"};function s(n,t,h,i,l,g){return o(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="移动机器人软硬件集成课程-ai-ros-2" tabindex="-1">移动机器人软硬件集成课程 (AI &amp; ROS 2) <a class="header-anchor" href="#移动机器人软硬件集成课程-ai-ros-2" aria-label="Permalink to &quot;移动机器人软硬件集成课程 (AI &amp; ROS 2)&quot;">​</a></h1><blockquote><p><strong>主题：教给孩子 AI 时代的生存逻辑，培养 AI 时代的科创人才</strong></p></blockquote><hr><h2 id="🏗️-页面架构说明" tabindex="-1">🏗️ 页面架构说明 <a class="header-anchor" href="#🏗️-页面架构说明" aria-label="Permalink to &quot;🏗️ 页面架构说明&quot;">​</a></h2><table tabindex="0"><thead><tr><th>层级</th><th>技术方案</th><th>描述</th></tr></thead><tbody><tr><td><strong>课程首页</strong></td><td>React SPA（当前页面）</td><td>提供课程概览、分类提纲、适用群体等高阶信息展示</td></tr><tr><td><strong>技术细节文档</strong></td><td>VitePress 静态站点</td><td>点击各章节链接后跳转，提供深度技术文档、实验指南与代码示例</td></tr></tbody></table><hr><h2 id="📌-课程定位" tabindex="-1">📌 课程定位 <a class="header-anchor" href="#📌-课程定位" aria-label="Permalink to &quot;📌 课程定位&quot;">​</a></h2><p><strong>时代之变（Why）：</strong> 2023 年人类步入 AI 原生时代，传统编程与制造门槛正被全面降维。未来科技人才的核心壁垒，不再是死记硬背的底层语法和机械接线，而是<strong>定义真实需求、驾驭 AI 工具进行系统性决策</strong>的能力。</p><p><strong>方法之新（How）：</strong> 本课程独创性地融合 <strong>开源造物精神（FabLab）、项目式学习（PBL）与工业级 AI 敏捷工作流</strong>。通过&quot;硬件统一，AI 赋能&quot;的超级工程放大器，赋能学生跨越跨学科技术鸿沟，完成从&quot;工具使用者&quot;到&quot;物理世界创造者&quot;的蜕变。</p><p><strong>成果之硬（What）：</strong> 课程以国家高素质科创人才鉴定标准为导向。通过对比 3 种以上 AI 方案、BOM 成本优化和 DFM 审查，引导学生打造出打通&quot;端-网-云&quot;的具身智能机器人以及工业级开源作品集，为国内强基综评与海外顶尖名校申请做储备。</p><hr><h2 id="🎯-适用群体-招生学员画像" tabindex="-1">🎯 适用群体（招生学员画像） <a class="header-anchor" href="#🎯-适用群体-招生学员画像" aria-label="Permalink to &quot;🎯 适用群体（招生学员画像）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>维度</th><th>描述</th></tr></thead><tbody><tr><td><strong>年龄段</strong></td><td>初一、初二、高一、高二</td></tr><tr><td><strong>基础门槛</strong></td><td>具备一定的英语、科学、基础编程或机器人操作经验</td></tr><tr><td><strong>核心兴趣</strong></td><td>对人工智能、具身智能、产品创新及硬核科技竞赛有浓厚探索欲的初高中生</td></tr><tr><td><strong>核心诉求</strong></td><td>有国内升学（强基计划、综合评价、科创特长）或海外顶尖名校申请需求，渴望建立含金量极高、符合工业标准的个人项目作品集</td></tr></tbody></table><hr><h2 id="📋-分类提纲" tabindex="-1">📋 分类提纲 <a class="header-anchor" href="#📋-分类提纲" aria-label="Permalink to &quot;📋 分类提纲&quot;">​</a></h2><p>本课程按年龄和深度分为 <strong>初中组</strong> 和 <strong>高中组</strong> 两条路线：</p><h3 id="🟢-初中组-ai-机器人产品体验营" tabindex="-1">🟢 初中组：AI 机器人产品体验营 <a class="header-anchor" href="#🟢-初中组-ai-机器人产品体验营" aria-label="Permalink to &quot;🟢 初中组：AI 机器人产品体验营&quot;">​</a></h3><blockquote><p><strong>核心理念：</strong> &quot;AI 做所有事，学生只做决策&quot;</p></blockquote><table tabindex="0"><thead><tr><th>阶段</th><th>天数</th><th>主题</th><th>核心内容</th></tr></thead><tbody><tr><td><strong>需求定义</strong></td><td>Day 1-2</td><td>问题挖掘 &amp; 功能定义</td><td>痛点分析、用户画像、提示词工程、PRD 撰写、概念外观文生图</td></tr><tr><td><strong>结构设计</strong></td><td>Day 3</td><td>参数化设计与数字制造</td><td>CMF/DFM 规范、参数化建模（sophicar.com）、3D 打印与激光切割</td></tr><tr><td><strong>嵌入式开发</strong></td><td>Day 4-6</td><td>嵌入式基础与软硬件调试</td><td>ESP32-S3 引脚认知、Wokwi 仿真、自然语言控制开发、CAN 总线通信</td></tr><tr><td><strong>全栈集成</strong></td><td>Day 7-8</td><td>Vibe Coding &amp; 多模态交互</td><td>Web/小程序零代码界面、跨网无线控制、语音/视觉 AI 融合</td></tr><tr><td><strong>数字孪生</strong></td><td>Day 9-10</td><td>仿真与系统优化</td><td>Three.js 3D 数字孪生、虚实联动、轻量化结构优化</td></tr><tr><td><strong>发布路演</strong></td><td>Day 11-12</td><td>包装与产品发布</td><td>压力测试、文档优化、5 分钟技术路演 + Q&amp;A</td></tr></tbody></table><h3 id="🔵-高中组-ai-具身智能产品工程营" tabindex="-1">🔵 高中组：AI 具身智能产品工程营 <a class="header-anchor" href="#🔵-高中组-ai-具身智能产品工程营" aria-label="Permalink to &quot;🔵 高中组：AI 具身智能产品工程营&quot;">​</a></h3><blockquote><p><strong>核心理念：</strong> &quot;AI 做基础执行，学生做系统设计和深度决策&quot;</p></blockquote><p><strong>与初中组的本质区别：</strong></p><ul><li>从&quot;单点生成&quot;升级为 <strong>多智能体协作流（Multi-Agent Workflow）</strong></li><li>独创&quot;AI 生成复杂要素 → 学生白盒机理剖析 → 仿真验证 → 物理实操重构&quot;逆向工程流</li><li>交付包含 <strong>数理公式推导、定量分析图表、Git Commit 全留痕证据链</strong> 的学术型开源作品集</li></ul><table tabindex="0"><thead><tr><th>阶段</th><th>天数</th><th>主题</th><th>核心内容</th></tr></thead><tbody><tr><td><strong>商业定义</strong></td><td>Day 1-2</td><td>社会痛点 &amp; 功能定义</td><td>SDG 关联分析、专利检索、商业可行性报告、全局技术拓扑图</td></tr><tr><td><strong>结构设计</strong></td><td>Day 3-4</td><td>参数化设计与数字制造</td><td>参数化建模、BOM 成本优化、供应链采购分析</td></tr><tr><td><strong>嵌入式开发</strong></td><td>Day 5-6</td><td>嵌入式与传感器融合</td><td>运动学反解推导、CAN 总线通信、机械臂控制、多传感器融合</td></tr><tr><td><strong>全栈集成</strong></td><td>Day 7-8</td><td>Vibe Coding &amp; 交互</td><td>MQTT/WiFi 长连接、VLM 多模态指令流、YOLO 视觉识别</td></tr><tr><td><strong>数字孪生</strong></td><td>Day 9-10</td><td>仿真与系统优化</td><td>Three.js 数字孪生、Generative Design 拓扑优化</td></tr><tr><td><strong>发布路演</strong></td><td>Day 11-12</td><td>包装与产品发布</td><td>学术型技术报告、GitHub 开源仓库规范、产品发布会</td></tr></tbody></table><hr><h2 id="💡-核心教学理念" tabindex="-1">💡 核心教学理念 <a class="header-anchor" href="#💡-核心教学理念" aria-label="Permalink to &quot;💡 核心教学理念&quot;">​</a></h2><ul><li><strong>角色定位</strong>：从&quot;技术学习者&quot;到&quot;项目决策者&quot;——AI 降维了跨学科技术门槛，让学生从&quot;学代码语法&quot;变成&quot;做产品解决真实问题&quot;</li><li><strong>师资重塑</strong>：从&quot;知识灌输者&quot;到&quot;提示词导师&quot;——教师引导学生向 AI 正确提问，并陪伴在物理世界中落地</li><li><strong>敏捷形态</strong>：首创&quot;双人精锐组 + 第三队员 AI Agent&quot;的敏捷开发模式</li><li><strong>成果交付</strong>：打通&quot;端-网-云-虚拟仿真&quot;的具身智能移动机器人 + 工业级开源作品集</li></ul><hr><h2 id="📚-技术文档章节-vitepress-详情页" tabindex="-1">📚 技术文档章节（VitePress 详情页） <a class="header-anchor" href="#📚-技术文档章节-vitepress-详情页" aria-label="Permalink to &quot;📚 技术文档章节（VitePress 详情页）&quot;">​</a></h2><p>点击以下章节即可跳转查看技术文档细节及实验指南：</p><h3 id="第一章-机器人运动学与动力学建模" tabindex="-1"><a href="./theory.html">第一章：机器人运动学与动力学建模</a> <a class="header-anchor" href="#第一章-机器人运动学与动力学建模" aria-label="Permalink to &quot;[第一章：机器人运动学与动力学建模](./theory.md)&quot;">​</a></h3><ul><li><strong>核心理论</strong>: 深入推导双轮差速底盘及麦克纳姆全向轮底盘的正逆解运动矩阵，理解航向估计（Odometry）和 Pure Pursuit 路径追踪。</li><li><a href="./theory.html">点击查看运动学细节文档 →</a></li></ul><h3 id="第二章-底盘控制链与微处理器集成" tabindex="-1"><a href="./hardware.html">第二章：底盘控制链与微处理器集成</a> <a class="header-anchor" href="#第二章-底盘控制链与微处理器集成" aria-label="Permalink to &quot;[第二章：底盘控制链与微处理器集成](./hardware.md)&quot;">​</a></h3><ul><li><strong>底层执行</strong>: 学习增量式 PID 电机闭环控制原理，掌握算能 Sophigo Duo 的 GPIO/PWM/UART 引脚分配与防干扰电机驱动硬件设计。</li><li><a href="./hardware.html">点击查看控制与硬件集成细节 →</a></li></ul><h3 id="第三章-ros2-导航与感知系统" tabindex="-1"><a href="./ros2.html">第三章：ROS2 导航与感知系统</a> <a class="header-anchor" href="#第三章-ros2-导航与感知系统" aria-label="Permalink to &quot;[第三章：ROS2 导航与感知系统](./ros2.md)&quot;">​</a></h3><ul><li><strong>中枢大脑</strong>: 部署 ROS2 通信节点，广播车体 TF2 坐标变换，接入激光雷达并通过 Nav2 导航堆栈实现 SLAM 建图及自主避障规划。</li><li><a href="./ros2.html">点击查看ROS2导航系统细节 →</a></li></ul><h3 id="第四章-sophicar-3d-在线仿真" tabindex="-1"><a href="./simulation.html">第四章：Sophicar 3D 在线仿真</a> <a class="header-anchor" href="#第四章-sophicar-3d-在线仿真" aria-label="Permalink to &quot;[第四章：Sophicar 3D 在线仿真](./simulation.md)&quot;">​</a></h3><ul><li><strong>仿真演练</strong>: 利用 WebGL (Three.js) 在线渲染 Sophicar 精准车身 CAD 结构，通过网页虚拟遥控器及虚拟传感器射线在零硬件条件下验证控制程序。</li><li><a href="./simulation.html">点击查看Web 3D仿真细节 →</a></li></ul><hr><h2 id="🏆-课程产出" tabindex="-1">🏆 课程产出 <a class="header-anchor" href="#🏆-课程产出" aria-label="Permalink to &quot;🏆 课程产出&quot;">​</a></h2><table tabindex="0"><thead><tr><th>产出类别</th><th>详细内容</th></tr></thead><tbody><tr><td><strong>实物项目</strong></td><td>带走属于你的第一台物理 AI 移动机器人</td></tr><tr><td><strong>网页 &amp; 开源仓库</strong></td><td>GitHub/Gitee 仓库（底层代码、Prompt 系统、前端控制界面源码、3D 打印 <code>.STL</code> 文件）</td></tr><tr><td><strong>工程日志</strong></td><td>科学记录格式：[工程问题] → [数据/Bug] → [AI Prompt 迭代] → [解决方案] → [物理验证与反思]</td></tr><tr><td><strong>演示视频</strong></td><td>参考 Kickstarter 众筹视频规格，全英文/中文技术路演</td></tr><tr><td><strong>认证证书</strong></td><td>学校、企业、Sophilab 联合发布的结营证书</td></tr></tbody></table><hr><h2 id="💬-划词批注互动区" tabindex="-1">💬 划词批注互动区 <a class="header-anchor" href="#💬-划词批注互动区" aria-label="Permalink to &quot;💬 划词批注互动区&quot;">​</a></h2><p>本平台已集成<strong>高保真本地划词评论系统</strong>。如果您对运动学矩阵推导、引脚连线图或者 ROS2 节点通信存在任何疑问：</p><ol><li>请先在<a href="/docs/">主站首页</a>注册并登录。</li><li>返回本页面，<strong>用鼠标直接划选目标文字</strong>，即可触发高亮批注面板进行提问或讨论。</li><li>您的疑问将会显示在对应文本行下，助您与社区极客共同进步！</li></ol>',45)])])}const q=r(e,[["render",s]]);export{b as __pageData,q as default};
